impl CronDaily {
    fn validate(&self, errors: &mut Vec<ValidationError>) -> bool {
        let neb = errors.len();
        let value = &self.hour;
        if *value > 23 {
            errors.push(ValidationError::max_value(Property::Hour, 23));
        }
        let value = &self.minute;
        if *value > 59 {
            errors.push(ValidationError::max_value(Property::Minute, 59));
        }
        errors.len() == neb
    }
}

