impl DnsResolverCustom {
    fn validate(&self, errors: &mut Vec<ValidationError>) -> bool {
        let neb = errors.len();
        let value = &self.servers;
        for value in value.values() {
            value.validate(errors);
        }
        if value.len() < 1 {
            errors.push(ValidationError::min_items(Property::Servers, 1));
        }
        errors.len() == neb
    }
}

